(320, 1715, 8, 1343, 'Legal Auditor', 'المستند المرفق سليم \nمطلوب ارفاق مستندات تعزز المستند المرفق', '2026-04-02 16:15:09', '2026-04-04 14:41:37'),
(321, 1702, 7, 1342, 'Legal Auditor', 'لا يمكن اعتماد المبنى في المرحلة الحالية لعدم وجود دليل قانوني كافٍ يثبت حق الملكية أو الانتفاع  بالمبنى وهذا ينطبق على الوحدات  \n		\nيجب ارفاق سند  ملكية حسب الأصول القانونية', '2026-04-02 16:15:30', '2026-04-02 16:28:24'),
(322, 1791, 7, 1342, 'Legal Auditor', 'بعد التدقيق القانوني للمستندات المرفقة، تبيّن أنها كافية لإثبات علاقة مقدم الطلب بالمبنى محل الطلب وفق معايير التحقق المعتمدة، وعليه يُوصى باعتماد المبني.', '2026-04-02 16:15:30', '2026-04-02 16:36:48'),
(323, 8035, 7, 1342, 'Legal Auditor', 'يحب ارفاق سند فاتورة', '2026-04-02 16:15:31', '2026-04-02 16:34:35'),
(324, 1696, 8, 1342, 'Legal Auditor', 'بعد التدقيق القانوني للمستندات المرفقة، تبيّن أنها كافية لإثبات علاقة مقدم الطلب بالمبنى محل الطلب وفق معايير التحقق المعتمدة، وعليه يُوصى باعتماد المبني.', '2026-04-02 16:15:31', '2026-04-02 16:37:23'),
