(1121, 4052, 8, 1344, 'Legal Auditor', 'مقبول مع ارفاق رخصة البناء إن أمكن', '2026-04-07 18:03:28', '2026-04-07 19:48:04'),
(1122, 9645, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة.', '2026-04-07 18:03:28', '2026-04-07 19:49:43'),
(1123, 8005, 8, 1344, 'Legal Auditor', 'الملكية سليمة', '2026-04-07 18:03:28', '2026-04-07 20:43:44'),
(1124, 1681, 8, 1344, 'Legal Auditor', 'الملكية سليمة', '2026-04-07 18:03:28', '2026-04-07 20:09:24'),
(1125, 4122, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.. والسند المرفق غير موضح فيه المساحة ولا رقم القسيمة والقطعة غير كافي لإثبات الملكية. ضرورة استخراج رخصة البناء من البلدية.', '2026-04-07 18:03:28', '2026-04-07 20:15:24'),
(1126, 5373, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.', '2026-04-07 18:03:28', '2026-04-07 20:24:21'),
(1127, 7821, 7, 1344, 'Legal Auditor', 'الملك حسب السندات المرفقة هو كامل راتب أحمد شعت.. وغير موضح إن كان موجود أم متوفي! وإن كان متوفي غير مرفقة حجة حصر ارث من المحكمة الشرعية.. ولا سند قسمة إن تعددوا الورثة موقع من جميعهم.', '2026-04-07 18:03:29', '2026-04-07 20:39:27'),
(1128, 7986, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.', '2026-04-07 18:03:29', '2026-04-07 20:44:55'),
(1129, 3622, 7, 1344, 'Legal Auditor', 'وثاق وسندات الملكية غير مرفقة أعلاه.. والسند المرفق غير كافي لإثبات الملكية.', '2026-04-07 18:03:29', '2026-04-07 20:47:51'),
