(1391, 6964, 7, 1344, 'Legal Auditor', 'المالك شهيد متوفي.. وغير مرفق حجة حصر ارث من المحكمة الشرعية ولا سند اتفاق على قسمة بين الورثة موقع من الجميع أو أي  سندات أخرى تبين نصيب كل وارث بالنسبة للمبنى والأرض.', '2026-04-07 21:10:16', '2026-04-07 22:06:41'),
(1392, 2614, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه', '2026-04-07 21:10:16', '2026-04-07 22:10:06'),
(1393, 8596, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.', '2026-04-07 21:10:17', '2026-04-08 15:57:12'),
(1394, 7298, 7, 1344, 'Legal Auditor', 'السندات المرفقة يختلف ما هو مذكور بمتنها عن ما جاء في استبيان والبيانات الخاصة بالمبنى التي ذكرها مهندس الحصر المُكلّف هنا.. يرجى ارفاق وثائق وسندات مكيلة تثبت بأن المبنى هذا ملك لعامر الفيومي المتوفي ثم آل لورثته بالميراث.', '2026-04-07 21:10:17', '2026-04-08 16:38:07'),
(1395, 1992, 7, 1344, 'Legal Auditor', 'المالك متوفي.. وغير مرفق حجة حصر ارث من المحكمة الشرعية... ولا سند اتفاق على قسمة بين الورثة موقع من الجميع,, أو أي وثائق أخرى تحسم الأمر وتبيّن نصيب كل منهم في ملكية المبنى.', '2026-04-07 21:10:17', '2026-04-08 17:35:55'),
(1396, 7765, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.', '2026-04-07 21:10:17', '2026-04-08 17:45:09'),
(1397, 5414, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة أعلاه.. والسند المرفق غير كافي لإثبات الملكية.', '2026-04-07 21:10:17', '2026-04-08 17:48:48'),
(1398, 5866, 8, 1344, 'Legal Auditor', 'يستحسن ارفاق سند القسيمة الرضائية المحرر ب 1998 المذكورة بالعقد المرفق لتأكيد وتوضيح المساحة ومطابقتها مع البيانات المذكورة من قبل مهندس الحصر هنا.', '2026-04-07 21:10:17', '2026-04-08 17:55:32'),
(1399, 5179, 8, 1344, 'Legal Auditor', 'تم لكن موقع العقار التفاح', '2026-04-07 21:10:17', '2026-04-13 19:04:20'),
(1400, 6433, 8, 1344, 'Legal Auditor', 'تم', '2026-04-07 21:10:18', '2026-04-08 17:57:57'),
(1401, 4586, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة.. والسند المرفق فاتورة غير كافي لإثبات الملكية', '2026-04-07 21:10:18', '2026-04-13 19:09:50'),
(1402, 6686, 8, 1344, 'Legal Auditor', 'تم مع ارفاق رخصة البناء', '2026-04-07 21:10:18', '2026-04-13 19:15:20'),
(1403, 7086, 8, 1344, 'Legal Auditor', 'تم مع ارفاق رخصة البناء', '2026-04-07 21:10:18', '2026-04-13 19:41:51'),
(1404, 5093, 8, 1344, 'Legal Auditor', 'الملكية على الشيوع وغير مرفق سند قسمة أموال مشتركة (العقار) موقع من المالكيين.. ضرورة ارفاق رخصة البناء وتقسيم وحدات وطوابق المبنى بين المالكين على الشيوع بموجب سند بذلك.', '2026-04-07 21:10:18', '2026-04-13 20:03:53'),
(1405, 5701, 8, 1344, 'Legal Auditor', 'الملكية مشتركة بين منال أبو دية وسابقًا المدهون وبين علاء محمد أبو دية', '2026-04-07 21:10:18', '2026-04-13 20:16:38'),
(1406, 5212, 7, 1344, 'Legal Auditor', 'وثائق وسندات الملكية غير مرفقة والسند المرفق غير كافي لإثبات الملكية', '2026-04-07 21:10:19', '2026-04-08 22:36:03'),
(1407, 5486, 7, 1344, 'Legal Auditor', 'أولًا قرار التحكيم غير كامل صفحاته\nثانيًا القسمة الرضائية المرفقة للعديد من عقارات الموروثة وفي هذا المبنى القائم غير مرفق سند قسمة بشأنه يوضح نصيب كل وارث لأرض المبنى بالنسبة للبناء .. لذا ضرورة ارفاق رخصة البناء .. كما أن المالك ميناوي مطر متوفي ولم يتم ارفاق حجة حصر ارث من المحكمة الشرعية ولا سند اتفاق على قسمة بين ورثته موقع من الجميع.', '2026-04-07 21:10:19', '2026-04-13 16:42:31'),
(1408, 4839, 8, 1344, 'Legal Auditor', 'تم.. لكن يوجد خطأ مادي في هوية المالك (المشتري) في العقد المرفق، ناقص رقم 9 الأخير.', '2026-04-07 21:10:19', '2026-04-13 17:16:35'),
(1409, 9650, 8, 1344, 'Legal Auditor', 'لكن الملكية فردية', '2026-04-07 21:10:19', '2026-04-13 17:26:20'),
