(1411, 6189, 8, 1344, 'Legal Auditor', 'تم مع ارفاق رخصة البناء', '2026-04-07 21:10:20', '2026-04-13 17:47:54'),
(1412, 5575, 8, 1344, 'Legal Auditor', 'مع ارفاق رخصة البناء', '2026-04-07 21:10:20', '2026-04-13 18:12:24'),
